mapper.select:
SELECT id, equip_type, check_year, check_month,
       detail, cycle, plan_months, check_detail,
       checker, check_note, check_data_before, check_data_after,
       data_before_note, note, user_code, reg_date
FROM tb_annual_check_result
WHERE check_year  = #{checkYear}
  AND check_month = #{checkMonth}
  AND equip_type  = #{equipType}
ORDER BY id
